xpath.script:
(function() {
    var baseUrl         = '';
    var apiCalled       = '';
    var color           = '';
    var token           = '';
    var position        = '';
    var iconType        = '';
    var size            = '';
    var iconDesk        = '';
    var noEu            = '';
    var precise         = '';
    var customSize      = '';
    var customSizePx    = parseInt('') || 50;
    var offsetRight     = parseInt('') || 20;
    var offsetRightDir  = '';
    var offsetBottom    = parseInt('') || 20;
    var offsetBottomDir = '';

    var domain = baseUrl;
    if (baseUrl.indexOf('://') !== -1) {
        var parts = baseUrl.split('://');
        var host  = parts[1].split('/')[0].split(':')[0];
        domain    = parts[0] + '://' + host;
    }

    function setParam(key, value) {
        return fetch('/web/dataset/call_kw', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                jsonrpc: '2.0',
                method:  'call',
                params:  {
                    model:  'ir.config_parameter',
                    method: 'set_param',
                    args:   [key, value],
                    kwargs: {}
                }
            })
        });
    }

    // 1. Register domain once on first install — fire and forget, no reload
    if (apiCalled !== 'True') {
        var domainName = domain.split('://')[1] || domain;
        fetch('https://ada.skynettechnologies.us/api/add-user-domain', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                name:            domainName,
                email:           'no-reply@' + domainName,
                company_name:    '',
                website:         btoa(domain),
                package_type:    'free-widget',
                start_date:      new Date().toISOString(),
                end_date:        '',
                price:           '',
                discount_price:  '0',
                platform:        'Odoo',
                api_key:         '',
                is_trial_period: '',
                is_free_widget:  '1',
                bill_address:    '',
                country:         '',
                state:           '',
                city:            '',
                post_code:       '',
                transaction_id:  '',
                subscr_id:       '',
                payment_source:  '',
                no_required_eu:  noEu === '0' ? 0 : 1
            }),
            mode: 'no-cors'
        }).then(function() {
            setParam('odoo_allinoneaccessibility.api_called', 'True');
        }).catch(function() {
            setParam('odoo_allinoneaccessibility.api_called', 'True');
        });
    }

    // 2. Always sync current settings to external API on page load.
    //    Uses localStorage to avoid spamming the API on every visit —
    //    only syncs when the stored settings hash differs from current.
    //    NO window.location.reload() anywhere — zero extra page loads.
    (function syncWidgetSettings() {
        var payload = {
            u:                         domain,
            widget_color_code:         '#' + color,
            widget_icon_type:          iconType,
            widget_position:           precise === 'True' ? '' : position,
            widget_size:               size === 'oversize' ? 1 : 0,
            is_widget_custom_position: precise === 'True' ? 1 : 0,
            is_widget_custom_size:     customSize === 'True' ? 1 : 0
        };

        if (customSize === 'True') {
            payload.widget_icon_size        = '';
            payload.widget_icon_size_custom = customSizePx;
        } else {
            payload.widget_icon_size        = iconDesk;
            payload.widget_icon_size_custom = 0;
        }

        if (precise === 'True') {
            payload.widget_position_right      = offsetRight;
            payload.widget_position_right_dir  = offsetRightDir;
            payload.widget_position_bottom     = offsetBottom;
            payload.widget_position_bottom_dir = offsetBottomDir;
        }

        // Only call the API if settings have changed since last sync
        var currentHash = JSON.stringify(payload);
        var lastHash    = '';
        try { lastHash = localStorage.getItem('aioa_last_sync') || ''; } catch(e) {}

        if (currentHash === lastHash) {
            return; // Nothing changed, skip API call
        }

        var xhr = new XMLHttpRequest();
        xhr.open('POST', 'https://ada.skynettechnologies.us/api/widget-setting-update-platform', true);
        xhr.setRequestHeader('Content-Type', 'application/json');
        xhr.onload = function() {
            // Save hash so we don't re-sync until settings change again
            try { localStorage.setItem('aioa_last_sync', currentHash); } catch(e) {}
            try { localStorage.removeItem('widgetSettings'); } catch(e) {}
            // NO reload here — widget script tag already has updated params
            // in its src URL, so it will load fresh settings automatically
        };
        xhr.onerror = function() {
            // On error, don't save hash so it retries next page load
        };
        xhr.send(JSON.stringify(payload));
    })();

})();
